import { Link } from "react-router-dom";

function HomePage() {
  const storedUser = localStorage.getItem("user");
  const user = storedUser ? JSON.parse(storedUser) : null;

  return (
    <div
      style={{
        minHeight: "100vh",
        background: "linear-gradient(135deg, #667eea, #764ba2, #f093fb)",
        padding: "40px 20px",
        color: "white",
      }}
    >
      <div
        style={{
          maxWidth: "1100px",
          margin: "0 auto",
          textAlign: "center",
        }}
      >
        <h1 style={{ fontSize: "3rem", marginBottom: "10px" }}>
          Cloud Event Management Platform
        </h1>

        <p style={{ fontSize: "1.2rem", marginBottom: "30px" }}>
          Manage events, register users, and experience a modern cloud-based event system.
        </p>

        {user ? (
          <p
            style={{
              backgroundColor: "rgba(255,255,255,0.2)",
              display: "inline-block",
              padding: "10px 20px",
              borderRadius: "20px",
              marginBottom: "30px",
            }}
          >
            Welcome back, <strong>{user.name}</strong> ({user.role})
          </p>
        ) : (
          <p
            style={{
              backgroundColor: "rgba(255,255,255,0.2)",
              display: "inline-block",
              padding: "10px 20px",
              borderRadius: "20px",
              marginBottom: "30px",
            }}
          >
            Please login or signup to continue
          </p>
        )}

        <div style={{ marginBottom: "40px" }}>
          <Link to="/events">
            <button
              style={{
                margin: "10px",
                padding: "14px 24px",
                border: "none",
                borderRadius: "10px",
                backgroundColor: "#ffcc70",
                color: "#222",
                fontWeight: "bold",
                cursor: "pointer",
              }}
            >
              View Events
            </button>
          </Link>

          {!user && (
            <Link to="/login">
              <button
                style={{
                  margin: "10px",
                  padding: "14px 24px",
                  border: "none",
                  borderRadius: "10px",
                  backgroundColor: "#70e1f5",
                  color: "#222",
                  fontWeight: "bold",
                  cursor: "pointer",
                }}
              >
                Login
              </button>
            </Link>
          )}

          {!user && (
            <Link to="/register">
              <button
                style={{
                  margin: "10px",
                  padding: "14px 24px",
                  border: "none",
                  borderRadius: "10px",
                  backgroundColor: "#ffd194",
                  color: "#222",
                  fontWeight: "bold",
                  cursor: "pointer",
                }}
              >
                Signup
              </button>
            </Link>
          )}

          {user && (
            <Link to="/my-registrations">
              <button
                style={{
                  margin: "10px",
                  padding: "14px 24px",
                  border: "none",
                  borderRadius: "10px",
                  backgroundColor: "#c2ffd8",
                  color: "#222",
                  fontWeight: "bold",
                  cursor: "pointer",
                }}
              >
                My Registrations
              </button>
            </Link>
          )}

          {user && user.role === "admin" && (
            <Link to="/create-event">
              <button
                style={{
                  margin: "10px",
                  padding: "14px 24px",
                  border: "none",
                  borderRadius: "10px",
                  backgroundColor: "#fff3b0",
                  color: "#222",
                  fontWeight: "bold",
                  cursor: "pointer",
                }}
              >
                Create Event
              </button>
            </Link>
          )}
        </div>

        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(auto-fit, minmax(250px, 1fr))",
            gap: "20px",
            marginTop: "30px",
          }}
        >
          <div
            style={{
              backgroundColor: "rgba(255,255,255,0.15)",
              padding: "25px",
              borderRadius: "20px",
              boxShadow: "0 4px 15px rgba(0,0,0,0.2)",
            }}
          >
            <h3>Event Creation</h3>
            <p>Admins can create and manage events easily in a cloud-based environment.</p>
          </div>

          <div
            style={{
              backgroundColor: "rgba(255,255,255,0.15)",
              padding: "25px",
              borderRadius: "20px",
              boxShadow: "0 4px 15px rgba(0,0,0,0.2)",
            }}
          >
            <h3>User Registration</h3>
            <p>Users can browse available events and register with a simple workflow.</p>
          </div>

          <div
            style={{
              backgroundColor: "rgba(255,255,255,0.15)",
              padding: "25px",
              borderRadius: "20px",
              boxShadow: "0 4px 15px rgba(0,0,0,0.2)",
            }}
          >
            <h3>Cloud Integration</h3>
            <p>The platform is designed for cloud deployment, monitoring, and scalable services.</p>
          </div>
        </div>
      </div>
    </div>
  );
}

export default HomePage;
